import React from 'react'
import { Avatar, Input } from 'antd'
import { UserOutlined, EyeTwoTone, EyeInvisibleOutlined } from '@ant-design/icons'
import './index.css'

export default function Login() {
  return (
    <div className='login'>
      <Avatar
        size={100}
      />
      <Input
        size='large'
        placeholder=''
        style={{
          width: '200px',
          marginBottom: "20px",
          marginTop: "30px"
        }}
        suffix={<UserOutlined />}
      ></Input>
      <Input.Password
        size='large'
        placeholder="input password"
        style={{
          width: '200px',
        }}
        prefix={(visible) => (visible ? <EyeTwoTone /> : <EyeInvisibleOutlined />)}
      />
    </div>
  )
}
